function changeSubscription(userId, currentPlan, newPlan) {
  if (!userId || typeof userId !== 'string') {
    throw new Error('Invalid userId');
  }

  if (!currentPlan || typeof currentPlan !== 'string') {
    throw new Error('Invalid currentPlan');
  }

  if (!newPlan || typeof newPlan !== 'string') {
    throw new Error('Invalid newPlan');
  }

  const validPlans = ['free', 'pro', 'enterprise'];

  const normalizedCurrentPlan = currentPlan.toLowerCase().trim();
  const normalizedNewPlan = newPlan.toLowerCase().trim();

  if (!validPlans.includes(normalizedCurrentPlan)) {
    throw new Error('Invalid current plan: ' + currentPlan);
  }

  if (!validPlans.includes(normalizedNewPlan)) {
    throw new Error('Invalid new plan: ' + newPlan);
  }

  if (normalizedCurrentPlan === normalizedNewPlan) {
    throw new Error('New plan must be different from current plan');
  }

  function getPlanPrice(plan) {
    if (plan === 'free') {
      return 0;
    } else if (plan === 'pro') {
      return 10;
    } else if (plan === 'enterprise') {
      return 50;
    }
  }

  const currentPrice = getPlanPrice(normalizedCurrentPlan);
  const newPrice = getPlanPrice(normalizedNewPlan);

  const priceDifference = newPrice - currentPrice;

  // Charge is the difference if upgrading (positive difference), 
  // or 0 if downgrading (we don't charge for downgrades; 
  // refund/credit logic would be handled separately)
  const charge = priceDifference > 0 ? priceDifference : 0;

  return {
    newPlan: normalizedNewPlan,
    charge: charge
  };
}

